def generate_saml_request():
    request_id = '_' + secrets.token_hex(20)
    issue_instant = datetime.utcnow().strftime('%Y-%m-%dT%H:%M:%SZ')
    
    saml_request = f'''<samlp:AuthnRequest xmlns:samlp="urn:oasis:names:tc:SAML:2.0:protocol"
        xmlns:saml="urn:oasis:names:tc:SAML:2.0:assertion"
        ID="{request_id}"
        Version="2.0"
        IssueInstant="{issue_instant}"
        Destination="{IDP_SSO_URL}"
        AssertionConsumerServiceURL="{SP_ACS_URL}"
        ProtocolBinding="urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST">
        <saml:Issuer>{SP_ENTITY_ID}</saml:Issuer>
        <samlp:NameIDPolicy Format="urn:oasis:names:tc:SAML:1.1:nameid-format:emailAddress" AllowCreate="true"/>
    </samlp:AuthnRequest>'''
    
    # Store request ID with timestamp for validation
    pending_requests[request_id] = {
        'timestamp': datetime.utcnow(),
        'used': False
    }
    
    # Clean old requests (older than 5 minutes)
    cleanup_old_requests()
    
    return request_id, saml_request

def cleanup_old_requests():
    current_time = datetime.utcnow()
    expired_ids = [
        req_id for req_id, data in pending_requests.items()
        if (current_time - data['timestamp']).total_seconds() > 300
    ]
    for req_id in expired_ids:
        del pending_requests[req_id]

def encode_saml_request(saml_request):
    compressed = zlib.compress(saml_request.encode('utf-8'))[2:-4]
    encoded = base64.b64encode(compressed).decode('utf-8')
    return quote(encoded)

def decode_saml_response(encoded_response):
    try:
        decoded = base64.b64decode(encoded_response)
        return decoded.decode('utf-8')
    except Exception as e:
        raise ValueError(f"Failed to decode SAML response: {str(e)}")

def validate_saml_response(xml_string):
    try:
        root = ET.fromstring(xml_string)
    except ET.ParseError as e:
        raise ValueError(f"Invalid XML: {str(e)}")
    
    # Check if it's a SAML Response
    if root.tag != f"{{{NAMESPACES['saml2p']}}}Response":
        raise ValueError("Not a valid SAML Response")
    
    # Validate Status
    status = root.find('.//saml2p:Status/saml2p:StatusCode', NAMESPACES)
    if status is None:
        raise ValueError("Missing Status element")
    
    status_code = status.get('Value')
    if status_code != 'urn:oasis:names:tc:SAML:2.0:status:Success':
        status_message = root.find('.//saml2p:Status/saml2p:StatusMessage', NAMESPACES)
        message = status_message.text if status_message is not None else "Unknown error"
        raise ValueError(f"SAML authentication failed: {message}")
    
    return root

def validate_assertion(assertion, in_response_to):
    # Validate InResponseTo
    if in_response_to:
        if in_response_to not in pending_requests:
            raise ValueError("Invalid InResponseTo: Request ID not found")
        
        if pending_requests[in_response_to]['used']:
            raise ValueError("Request ID already used (replay attack detected)")
        
        pending_requests[in_response_to]['used'] = True
    
    # Validate Issuer
    issuer = assertion.find('saml2:Issuer', NAMESPACES)
    if issuer is None or issuer.text != IDP_ENTITY_ID:
        raise ValueError("Invalid or missing Issuer")
    
    # Validate Subject
    subject = assertion.find('saml2:Subject', NAMESPACES)
    if subject is None:
        raise ValueError("Missing Subject element")
    
    # Validate Conditions
    conditions = assertion.find('saml2:Conditions', NAMESPACES)
    if conditions is not None:
        not_before = conditions.get('NotBefore')
        not_on_or_after = conditions.get('NotOnOrAfter')
        
        current_time = datetime.utcnow()
        
        if not_before:
            not_before_time = datetime.strptime(not_before, '%Y-%m-%dT%H:%M:%SZ')
            if current_time < not_before_time - timedelta(minutes=5):
                raise ValueError("Assertion not yet valid")
        
        if not_on_or_after:
            not_on_or_after_time = datetime.strptime(not_on_or_after, '%Y-%m-%dT%H:%M:%SZ')
            if current_time >= not_on_or_after_time:
                raise ValueError("Assertion expired")
        
        # Validate AudienceRestriction
        audience = conditions.find('.//saml2:Audience', NAMESPACES)
        if audience is not None and audience.text != SP_ENTITY_ID:
            raise ValueError("Invalid Audience")
    
    return True

def extract_user_attributes(assertion):
    user_data = {}
    
    # Extract NameID
    name_id = assertion.find('.//saml2:Subject/saml2:NameID', NAMESPACES)
    if name_id is not None:
        user_data['name_id'] = name_id.text
        user_data['name_id_format'] = name_id.get('Format', '')
    
    # Extract attributes
    attributes = assertion.findall('.//saml2:AttributeStatement/saml2:Attribute', NAMESPACES)
    
    for attr in attributes:
        attr_name = attr.get('Name')
        attr_values = attr.findall('saml2:AttributeValue', NAMESPACES)
        
        if len(attr_values) == 1:
            user_data[attr_name] = attr_values[0].text
        elif len(attr_values) > 1:
            user_data[attr_name] = [av.text for av in attr_values]
    
    # Common attribute mappings
    attribute_mappings = {
        'http://schemas.xmlsoap.org/ws/2005/05/identity/claims/emailaddress': 'email',
        'http://schemas.xmlsoap.org/ws/2005/05/identity/claims/givenname': 'first_name',
        'http://schemas.xmlsoap.org/ws/2005/05/identity/claims/surname': 'last_name',
        'http://schemas.xmlsoap.org/ws/2005/05/identity/claims/name': 'full_name',
        'urn:oid:0.9.2342.19200300.100.1.3': 'email',
        'urn:oid:2.5.4.42': 'first_name',
        'urn:oid:2.5.4.4': 'last_name',
        'urn:oid:2.16.840.1.113730.3.1.241': 'display_name'
    }
    
    for saml_attr, simple_attr in attribute_mappings.items():
        if saml_attr in user_data and simple_attr not in user_data:
            user_data[simple_attr] = user_data[saml_attr]
    
    return user_data

def process_saml_response(saml_response):
    # Decode and parse SAML response
    xml_string = decode_saml_response(saml_response)
    
    # Validate response structure
    root = validate_saml_response(xml_string)
    
    # Get InResponseTo for validation
    in_response_to = root.get('InResponseTo')
    
    # Find assertions
    assertions = root.findall('.//saml2:Assertion', NAMESPACES)
    
    if not assertions:
        raise ValueError("No assertions found in SAML response")
    
    # Process first assertion (typically there's only one)
    assertion = assertions[0]
    
    # Validate assertion
    validate_assertion(assertion, in_response_to)
    
    # Extract user attributes
    user_data = extract_user_attributes(assertion)
    
    if not user_data:
        raise ValueError("No user attributes found in assertion")
    
    return user_data

