@app.route('/acs', methods=['POST'])
def acs():
    try:
        saml_response = request.form.get('SAMLResponse')
        
        if not saml_response:
            abort(400, description="Missing SAMLResponse parameter")
        
        # Process SAML response
        user_data = process_saml_response(saml_response)
        
        # Create user session
        session.permanent = True
        session['user'] = user_data
        session['authenticated_at'] = datetime.utcnow().isoformat()
        session['session_id'] = secrets.token_hex(16)
        
        # Redirect to home or relay state
        relay_state = request.form.get('RelayState', '/')
        
        # Sanitize relay state to prevent open redirect
        if relay_state.startswith('http://') or relay_state.startswith('https://'):
            relay_state = '/'
        
        return redirect(relay_state)
        
    except ValueError as e:
        abort(400, description=f"SAML validation error: {str(e)}")
    except Exception as e:
        abort(500, description=f"Internal error processing SAML response: {str(e)}")

